    data = np.array(dat)   # Convert to NumPy array for convenience

    # ----------------------------------------------------------------------
    # 2. Extract columns
    # ----------------------------------------------------------------------
    reference_speed = data[:, 0]
    error_left      = data[:, 1]
    error_right     = data[:, 2]
    speed_left      = data[:, 3]
    speed_right     = data[:, 4]
    delta_speed_rs  = data[:, 5]   # delta speed in rad/s
    delta_speed_au = np.zeros_like(reference_speed)

    # ----------------------------------------------------------------------
    # 3. Plot everything as a function of reference speed
    # ----------------------------------------------------------------------
    plt.figure(figsize=(12, 10))
    plt.suptitle("PI Controller Motor Data vs Reference Speed", fontsize=16)

    # ---- Plot 1: Errors ---------------------------------------------------
    plt.subplot(3, 1, 1)
    plt.plot(reference_speed, error_left, label='Error Left', linewidth=1.5)
    plt.plot(reference_speed, error_right, label='Error Right', linewidth=1.5)
    plt.grid(True)
    plt.xlabel("Reference Speed")
    plt.ylabel("Error")
    plt.legend()
    plt.title("Motor Errors")

    # ---- Plot 2: Motor Speeds ---------------------------------------------
    plt.subplot(3, 1, 2)
    plt.plot(reference_speed, speed_left, label='Speed Left (rad/s)', linewidth=1.5)
    plt.plot(reference_speed, speed_right, label='Speed Right (rad/s)', linewidth=1.5)
    plt.grid(True)
    plt.xlabel("Reference Speed")
    plt.ylabel("Speed (rad/s)")
    plt.legend()
    plt.title("Measured Motor Speeds")

    # ---- Plot 3: Delta Speeds ---------------------------------------------
    plt.subplot(3, 1, 3)
    plt.plot(reference_speed, delta_speed_rs, label='Δ Speed (rad/s)', linewidth=1.5)
    plt.plot(reference_speed, delta_speed_au, label='Δ Speed (other)', linestyle='--')
    plt.grid(True)
    plt.xlabel("Reference Speed")
    plt.ylabel("Delta Speed")
    plt.legend()
    plt.title("Delta Speeds")

